<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class RecurringController{
 public function index():void{Auth::requireLogin();$pdo=Database::connection();$rows=$pdo->query('SELECT r.*,c.display_name,p.label property_label,s.name service_name,u.name technician FROM recurring_services r JOIN customers c ON c.id=r.customer_id LEFT JOIN properties p ON p.id=r.property_id LEFT JOIN services s ON s.id=r.service_id LEFT JOIN users u ON u.id=r.assigned_user_id ORDER BY r.next_service_date')->fetchAll();View::render('portal/recurring/index',['title'=>'Recurring Services','rows'=>$rows,'customers'=>$pdo->query('SELECT id,display_name FROM customers ORDER BY display_name')->fetchAll(),'services'=>$pdo->query('SELECT id,name FROM services WHERE active=1 ORDER BY name')->fetchAll(),'users'=>$pdo->query("SELECT id,name FROM users WHERE status='active' ORDER BY name")->fetchAll()],'portal');}
 public function store():void{Auth::requireRole('owner','office','estimator');verify_csrf();$s=Database::connection()->prepare('INSERT INTO recurring_services(customer_id,property_id,service_id,name,frequency,interval_days,next_service_date,preferred_start_time,assigned_user_id,notes) VALUES(?,?,?,?,?,?,?,?,?,?)');$s->execute([(int)$_POST['customer_id'],($_POST['property_id']??'')?:null,($_POST['service_id']??'')?:null,trim($_POST['name']),$_POST['frequency'],($_POST['interval_days']??'')?:null,$_POST['next_service_date'],($_POST['preferred_start_time']??'')?:null,($_POST['assigned_user_id']??'')?:null,trim($_POST['notes']??'')]);AuditService::log('recurring.created','recurring_service',(int)Database::connection()->lastInsertId());flash('success','Recurring service created.');redirect('/portal/recurring');}
 public function generate():void{Auth::requireRole('owner','office');verify_csrf();$pdo=Database::connection();$due=$pdo->query("SELECT * FROM recurring_services WHERE active=1 AND next_service_date<=CURDATE()")->fetchAll();$count=0;foreach($due as $r){$num=next_number('JOB-');$start=$r['next_service_date'].' '.($r['preferred_start_time']?:'08:00:00');$end=date('Y-m-d H:i:s',strtotime($start.' +2 hours'));$pdo->prepare('INSERT INTO jobs(job_number,customer_id,property_id,service_summary,scheduled_start,scheduled_end,status,assigned_user_id,notes) VALUES(?,?,?,?,?,?,?,?,?)')->execute([$num,$r['customer_id'],$r['property_id'],$r['name'],$start,$end,'scheduled',$r['assigned_user_id'],$r['notes']]);$next=match($r['frequency']){'weekly'=>'+7 days','biweekly'=>'+14 days','monthly'=>'+1 month','quarterly'=>'+3 months','semiannual'=>'+6 months','annual'=>'+1 year',default=>'+'.max(1,(int)$r['interval_days']).' days'};$pdo->prepare('UPDATE recurring_services SET next_service_date=? WHERE id=?')->execute([date('Y-m-d',strtotime($r['next_service_date'].' '.$next)),$r['id']]);$count++;}AuditService::log('recurring.generated','job',null,['count'=>$count]);flash('success',$count.' recurring job(s) generated.');redirect('/portal/recurring');}
}
